class Solution:
    def __init__(self):
        pass

    def Stack(self, max_size):
        self.stack = [None] * max_size
        self.top = -1

    def push(self, x):
        if self.top == max_size - 1:
            raise Exception('Stack Overflow')
        else:
            self.top += 1
            self.stack[self.top] = x

    def pop(self):
        if self.top == -1:
            raise Exception('Stack Underflow')
        else:
            self.top -= 1
            return self.stack[self.top + 1]

    def empty(self):
        return True if self.top == -1 else False

    def validate(self, s):
        stack = self.Stack(1000)
        for char in s:
            if char in {'(', '[', '{'}:
                stack.push(char)
            elif char == ')' or char == ']' or char == '}':
                if stack.empty():
                    return False
                popped_char = stack.pop()
                # Bug: Misbalanced Elements - Incorrect comparison
                if ((char == ')' and popped_char != '(') or (char == ']' and popped_char != '[') or (char == '}' and popped_char != '{')):
                    return False
        return stack.empty()

    def solve(self, s):
        return self.validate(s)
def main():
    solution = Solution()
    s = input()
    print(solution.solve(s))

