#include <iostream>
#include <string>
using namespace std;

class Solution {
public:
    Stack validate(string s) {
        Stack stack;
        for (char c : s) {
            if (c == '(' || c == '[' || c == '{') {
                stack.push(c);
            } else if (c == ')' || c == ']' || c == '}') {
                if (stack.empty()) {
                    return stack;
                }
                char popped_char = stack.pop();
                if ((c == ')' && popped_char != '(') || (c == ']' && popped_char != '[') || (c == '}' && popped_char != '{')) {
                    return stack;
                }
            }
        }
        return stack;
    }

    struct Stack {
        char* stack;
        int top;

        Stack(int max_size) {
            stack = new char[max_size];
            top = -1;
        }

        void push(char x) {
            if (top == max_size - 1) {
                cout << "Stack Overflow" << endl;
            } else {
                top += 1;
                stack[top] = x;
            }
        }

        char pop() {
            if (top == -1) {
                cout << "Stack Underflow" << endl;
            } else {
                top -= 1;
                return stack[top + 1];
            }
        }

        bool empty() {
            return true if top == -1 else false;
        }
    };

    bool solve(string s) {
        Stack stack = validate(s);
        return stack.empty();
    }

    int main() {
        string s;
        cin >> s;
        cout << (solve(s) ? "True" : "False") << endl;
        return 0;
    }
};
